import { Type } from 'class-transformer';
import { IsBoolean, IsEnum, IsNumber, IsOptional, IsString, ValidateNested } from 'class-validator';
import { AfterLoad, Column, Entity, JoinColumn, JoinTable, ManyToMany, ManyToOne } from 'typeorm';

import { env } from '@Libs/env';

import { DayType } from '@Enums/Day';
import { MealPlan, PriceType, SurchargeFeeType, UnitType } from '@Enums/Hotel';
import { CustomerType } from '@Enums/Customer';

import { GeoCountry } from '@Entities/GeoCountry';
import { Hotel } from '@Entities/Hotel';
import { Room } from '@Entities/Room';
import { Season } from '@Entities/Season';

import { BaseEntity } from '@DBCommon/BaseEntity';
import { RangeAge } from '@DBCommon/RangeAge';
import { RangeDate } from '@DBCommon/RangeDate';

@Entity()
export class SurchargeFeeSetting extends BaseEntity {
  @Column({ nullable: true, default: env.defaultSource })
  @IsString()
  source: string;

  @Column({ enum: SurchargeFeeType, type: 'enum' })
  @IsEnum(SurchargeFeeType)
  type: SurchargeFeeType;

  @Column({ enum: PriceType, type: 'enum', default: PriceType.TA })
  @IsEnum(PriceType)
  priceType: PriceType;

  @Column({ type: 'enum', enum: MealPlan, nullable: true })
  @IsEnum(MealPlan)
  @IsOptional()
  mealPlan?: MealPlan;

  @ManyToMany(() => GeoCountry, { nullable: true, onDelete: 'CASCADE' })
  @JoinTable({ name: 'surcharge_fee_setting_countries' })
  @ValidateNested({ each: true })
  @Type(() => GeoCountry)
  @IsOptional()
  countries?: GeoCountry[];

  @ManyToMany(() => Room, { nullable: true, onDelete: 'CASCADE' })
  @JoinTable({ name: 'surcharge_fee_setting_rooms' })
  @ValidateNested({ each: true })
  @Type(() => Room)
  @IsOptional()
  rooms?: Room[];

  @ManyToOne(() => Season, season => season.id, { nullable: true })
  @Type(() => Season)
  @ValidateNested()
  season: Season;

  @Column({ type: 'jsonb' })
  periods: RangeDate[];

  @Column({ type: 'enum', enum: UnitType, default: UnitType.FIXED_AMOUNT })
  @IsEnum(UnitType)
  unitType: UnitType;

  /** Số tiền phụ phí VNĐ */
  @Column({ type: 'decimal', precision: 10, scale: 2, default: 0 })
  @IsNumber()
  amount: number;

  /** Áp dụng cho ngày nào trong tuần, lấy từ config mùa type = DAY */
  @Column({ type: 'enum', enum: DayType, nullable: true })
  @IsEnum(DayType)
  @IsOptional()
  dayType?: DayType;

  //#region  Điều kiện mới
  /** Đối tượng áp dụng*/
  @Column({ type: 'enum', enum: CustomerType })
  @IsEnum(CustomerType)
  customerType: CustomerType;

  @Column({ type: 'jsonb', nullable: true })
  @ValidateNested({ each: true })
  @Type(() => RangeAge)
  @IsOptional()
  ageRanges?: RangeAge[];
  //#endregion

  @ManyToOne(() => Hotel, h => h.surchargeFeeSettings, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'hotelId' })
  @ValidateNested()
  @Type(() => Hotel)
  hotel: Hotel;

  @Column()
  hotelId: number;

  @Column({ default: true })
  @IsBoolean()
  isActive: boolean;

  @AfterLoad()
  sortPeriods() {
    if (this.periods && Array.isArray(this.periods)) {
      this.periods.sort((a, b) => new Date(a.startDate).getTime() - new Date(b.startDate).getTime());
    }
  }
}

