import dayjs from 'dayjs';
import { isUndefined } from 'lodash';
import { NotFoundError } from 'routing-controllers';
import { Service } from 'typedi';
import { In } from 'typeorm';

import { CustomerType } from '@Enums/Customer';
import { SurchargeFeeType } from '@Enums/Hotel';

import { BusinessLogicError } from '@Errors/BusinessLogicError';
import { ErrorCode } from '@Errors/ErrorCode';

import { SurchargeFeeSetting } from '@Entities/SurchargeFeeSetting';
import { Hotel } from '@Entities/Hotel';

import { RangeAge } from '@DBCommon/RangeAge';
import { RangeDate } from '@DBCommon/RangeDate';

import { GeoCountryRepository } from '@Repositories/GeoCountryRepository';
import { HotelRepository } from '@Repositories/HotelRepository';
import { RoomRepository } from '@Repositories/RoomRepository';
import { SeasonRepository } from '@Repositories/SeasonRepository';
import { SurchargeFeeSettingRepository } from '@Repositories/SurchargeFeeSettingRepository';

import { SurchargeRateCalendarService } from '@Services/SurchargeRateCalendarService';
import {
  CreateSurchargeFeeSettingInput,
  CreateManySurchargeFeeSettingsInput,
  CreateSurchargeFeeSettingCustomerConfigInput,
  SurchargeFeeSettingQueryParamInput,
  UpdateSurchargeFeeSettingInput,
} from '@Services/types/SurchargeFeeSettingInput';

@Service()
export class SurchargeFeeSettingService {
  constructor(
    private readonly repo: SurchargeFeeSettingRepository,
    private readonly seasonRepo: SeasonRepository,
    private readonly hotelRepo: HotelRepository,
    private readonly countryRepo: GeoCountryRepository,
    private readonly roomRepo: RoomRepository,
    private readonly surchargeCalendarService: SurchargeRateCalendarService,
  ) { }

  /**
   * Validate format của periods
   */
  private validatePeriodsFormat(periods: RangeDate[]) {
    if (!periods || !Array.isArray(periods) || periods.length === 0) {
      throw new BusinessLogicError(ErrorCode.PERIODS_REQUIRED);
    }

    for (const dateRange of periods) {
      if (!dateRange.startDate || !dateRange.endDate) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }

      const startDate = dayjs(dateRange.startDate);
      const endDate = dayjs(dateRange.endDate);

      if (!startDate.isValid() || !endDate.isValid()) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }

      if (startDate.isAfter(endDate)) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }
    }
  }

  /**
   * Check trùng lặp dựa trên:
   * - Loại phụ phí (type)
   * - Thị trường khách (countries)
   * - Loại ngày áp dụng (dayType)
   * - Mùa/Sự kiện (seasonId)
   *
   * Nếu các điều kiện trên trùng hoàn toàn thì check:
   * - Mùa trùng mùa (cùng seasonId)
   * - Mùa trùng thời gian tùy chỉnh (periods overlap)
   * - Sự kiện trùng sự kiện (cùng eventId trong season)
   */
  private async checkDuplicate(
    hotelId: number,
    type: SurchargeFeeType,
    customerType: CustomerType,
    countryIds: number[],
    roomIds: number[],
    dayType: string | null,
    seasonId: number | null,
    periods: RangeDate[],
    ageRanges?: RangeAge[] | null,
    excludeId?: number,
  ) {
    const duplicate = await this.repo.findDuplicateStrict(
      hotelId,
      type,
      customerType,
      countryIds,
      roomIds,
      dayType,
      seasonId,
      periods,
      ageRanges,
      excludeId,
    );

    if (duplicate) {
      throw new BusinessLogicError(ErrorCode.SURCHARGE_FEE_SETTING_DUPLICATE);
    }
  }

  private normalizeAgeRanges(ageRanges?: RangeAge[]) {
    if (!ageRanges || ageRanges.length === 0) return ageRanges;
    return [...ageRanges].sort((a, b) => a.fromAge - b.fromAge);
  }

  private validateAgeRanges(ageRanges?: RangeAge[]) {
    if (!ageRanges) return;
    if (ageRanges.length === 0) {
      throw new BusinessLogicError(ErrorCode.AGE_RANGE_INVALID);
    }

    const normalized = this.normalizeAgeRanges(ageRanges);
