import dayjs from 'dayjs';
import { Service } from 'typedi';
import { QueryRunner } from 'typeorm';

import { DayType } from '@Enums/Day';

import { SurchargeFeeSetting } from '@Entities/SurchargeFeeSetting';
import { SurchargeRateCalendar } from '@Entities/SurchargeRateCalendar';

import { SurchargeRateCalendarRepository } from '@Repositories/SurchargeRateCalendarRepository';

@Service()
export class SurchargeRateCalendarService {
  constructor(private readonly calendarRepo: SurchargeRateCalendarRepository) { }

  async rebuildForSetting(setting: SurchargeFeeSetting): Promise<void> {
    if (!setting?.id) return;

    await this.calendarRepo.withTransaction(async queryRunner => {
      await queryRunner.manager
        .createQueryBuilder()
        .delete()
        .from('surcharge_rate_calendar')
        .where('"surchargeFeeSettingId" = :id', { id: setting.id })
        .execute();

      if (!setting.isActive || !setting.mealPlan || !setting.periods?.length) return;

      const rows = this.expandSetting(setting);
      if (!rows.length) return;

      await this.insertRows(rows, queryRunner);
    });
  }

  async rebuildForSettings(settings: SurchargeFeeSetting[]): Promise<void> {
    for (const setting of settings) {
      await this.rebuildForSetting(setting);
    }
  }

  private expandSetting(setting: SurchargeFeeSetting): Partial<SurchargeRateCalendar>[] {
    const rows: Partial<SurchargeRateCalendar>[] = [];
    const roomIds = setting.rooms?.map(room => room.id) ?? [];
    const targetRoomIds = roomIds.length ? roomIds : [null];
    const ageRanges = setting.ageRanges?.length ? [...setting.ageRanges].sort((a, b) => a.fromAge - b.fromAge) : [];

    setting.periods.forEach(period => {
      const start = dayjs(period.startDate).startOf('day');
      const end = dayjs(period.endDate).startOf('day');
      if (!start.isValid() || !end.isValid()) return;

      let cursor = start;
      while (cursor.isSame(end, 'day') || cursor.isBefore(end, 'day')) {
        if (this.matchDayType(cursor, setting.dayType)) {
          const rangesToApply = ageRanges.length ? ageRanges : [null];
          targetRoomIds.forEach(roomId => {
            rangesToApply.forEach(range => {
              rows.push({
                hotelId: setting.hotelId,
                roomId,
                stayDate: cursor.toDate(),
                mealPlan: setting.mealPlan,
                type: setting.type,
                customerType: setting.customerType,
                fromAge: range ? range.fromAge : null,
                toAge: range ? range.toAge : null,
                unitType: setting.unitType,
                amount: setting.amount,
                priceType: setting.priceType,
                source: setting.source,
                isActive: setting.isActive,
                surchargeFeeSettingId: setting.id,
              });
            });
          });
        }
        cursor = cursor.add(1, 'day');
      }
    });

    return rows;
  }

  private matchDayType(date: dayjs.Dayjs, dayType?: DayType | null) {
    if (!dayType) return true;
    const day = date.day();
    const isWeekend = day === 0 || day === 6;
    return dayType === DayType.WEEKEND ? isWeekend : !isWeekend;
  }

  private async insertRows(rows: Partial<SurchargeRateCalendar>[], queryRunner?: QueryRunner): Promise<void> {
    const chunkSize = 500;
    for (let i = 0; i < rows.length; i += chunkSize) {
      const builder = queryRunner
        ? queryRunner.manager.createQueryBuilder()
        : this.calendarRepo.createQueryBuilder('src');
      await builder.insert().into('surcharge_rate_calendar').values(rows.slice(i, i + chunkSize)).execute();
    }
  }
}

