  async partialUpdate(id: number, payload: UpdateSurchargeFeeSettingInput) {
    const entity = await this.repo.findById(id, { relations: ['season', 'hotel', 'countries', 'rooms'] });
    if (!entity) throw new NotFoundError(ErrorCode.SURCHARGE_FEE_SETTING_NOT_FOUND);

    if (payload.seasonId) {
      const season = await this.seasonRepo.findById(payload.seasonId);
      if (!season) throw new NotFoundError(ErrorCode.SEASON_NOT_FOUND);
      entity.season = season;
      entity.periods = season.periods;
    } else if (payload.periods) {
      entity.periods = payload.periods;
      entity.season = null;
    }

    if (payload.countries) {
      const countries = await this.countryRepo.find({
        where: { id: In(payload.countries) },
      });
      if (payload.countries.length > 0 && countries.length === 0)
        throw new BusinessLogicError(ErrorCode.COUNTRY_NOT_FOUND);
      entity.countries = countries;
    }

    if (payload.roomIds) {
      const rooms = await this.roomRepo.find({
        where: { id: In(payload.roomIds), hotelId: entity.hotelId },
      });
      if (payload.roomIds.length > 0 && rooms.length === 0)
        throw new BusinessLogicError(ErrorCode.ROOM_NOT_FOUND);
      entity.rooms = rooms;
    }

    if (payload.type) entity.type = payload.type;
    if (payload.customerType) entity.customerType = payload.customerType;
    if (payload.unitType) entity.unitType = payload.unitType;
    if (payload.amount) entity.amount = payload.amount;
    if (!isUndefined(payload.dayType)) entity.dayType = payload.dayType;
    if (!isUndefined(payload.isActive)) entity.isActive = payload.isActive;
    if (!isUndefined(payload.ageRanges)) {
      entity.ageRanges = this.normalizeAgeRanges(payload.ageRanges);
    }
    if (payload.mealPlan) entity.mealPlan = payload.mealPlan;

    entity.updatedBy = payload.updatedBy;

    this.validatePeriodsFormat(entity.periods);
    this.validateAgeRanges(entity.ageRanges);
    const countryIds = (entity.countries || []).map(c => c.id).sort((a, b) => a - b);
    const roomIds = (entity.rooms || []).map(r => r.id).sort((a, b) => a - b);
    await this.checkDuplicate(
      entity.hotel.id,
      entity.type,
      entity.customerType,
      countryIds,
      roomIds,
      entity.dayType,
      entity.season?.id ?? null,
      entity.periods,
      entity.ageRanges,
      id,
    );

    const saved = await this.repo.save(entity);
    if (!saved.rooms || saved.rooms.length === 0) saved.rooms = entity.rooms;
    await this.surchargeCalendarService.rebuildForSetting(saved);
    return saved;
  }

  async createMany(payload: CreateManySurchargeFeeSettingsInput) {
    const { customers, ...shared } = payload;
    if (!customers || customers.length === 0) {
      throw new BusinessLogicError(ErrorCode.CONFIG_NOT_FOUND);
    }

    const results = [];
    for (const customerConfig of customers) {
      const item: CreateSurchargeFeeSettingInput = this.buildItemFromConfig(shared, customerConfig);
      const created = await this.create(item);
      if (Array.isArray(created)) {
        results.push(...created);
      } else {
        results.push(created);
      }
    }

    return results;
  }

  private buildItemFromConfig(
    shared: Omit<CreateManySurchargeFeeSettingsInput, 'customers'>,
    customerConfig: CreateSurchargeFeeSettingCustomerConfigInput,
  ): CreateSurchargeFeeSettingInput {
    return {
      ...shared,
      customerType: customerConfig.customerType,
      ageRanges: customerConfig.ageRanges,
      amount: customerConfig.amount,
    };
  }

  async insertMany(req: CreateSurchargeFeeSettingInput[], hotel?: Hotel) {
    const items = [];
    for (const input of req) {
      const item = new SurchargeFeeSetting();
      Object.assign(item, input);
      if (!item.customerType) item.customerType = CustomerType.ADULT;
      if (item.ageRanges) {
        item.ageRanges = this.normalizeAgeRanges(item.ageRanges);
      }
      this.validateAgeRanges(item.ageRanges);
      if (hotel) item.hotel = hotel;
      items.push(item);
    }

    return this.repo.insertMany(items);
  }
}

