  async partialUpdate(id: number, payload: UpdateSurchargeFeeSettingInput) {
    const entity = await this.repo.findById(id, { relations: ['season', 'hotel', 'countries', 'rooms'] });
    if (!entity) throw new NotFoundError(ErrorCode.SURCHARGE_FEE_SETTING_NOT_FOUND);

    if (payload.seasonId) {
      const season = await this.seasonRepo.findById(payload.seasonId);
      if (!season) throw new NotFoundError(ErrorCode.SEASON_NOT_FOUND);
      entity.season = season;
      entity.periods = season.periods;
    } else if (payload.periods) {
      entity.periods = payload.periods;
      entity.season = null;
    }

    if (payload.countries) {
      const countries = await this.countryRepo.find({
        where: { id: In(payload.countries) },
      });
      if (payload.countries.length > 0 && countries.length === 0)
        throw new BusinessLogicError(ErrorCode.COUNTRY_NOT_FOUND);
      entity.countries = countries;
    }

    if (payload.roomIds) {
      const rooms = await this.roomRepo.find({
        where: { id: In(payload.roomIds), hotelId: entity.hotelId },
      });
      if (payload.roomIds.length > 0 && rooms.length === 0)
        throw new BusinessLogicError(ErrorCode.ROOM_NOT_FOUND);
      entity.rooms = rooms;
    }

    if (payload.type) entity.type = payload.type;
    if (payload.customerType) entity.customerType = payload.customerType;
    if (payload.unitType) entity.unitType = payload.unitType;
    if (payload.amount) entity.amount = payload.amount;
    if (!isUndefined(payload.dayType)) entity.dayType = payload.dayType;
    if (!isUndefined(payload.isActive)) entity.isActive = payload.isActive;
    if (!isUndefined(payload.details)) {
