    const saved = await this.repo.save(entity);
    if (!saved.rooms || saved.rooms.length === 0) saved.rooms = entity.rooms;
    await this.surchargeCalendarService.rebuildForSetting(saved);
    return saved;
  }

  async createMany(payload: CreateManySurchargeFeeSettingsInput) {
    const { customers, ...shared } = payload;
    if (!customers || customers.length === 0) {
      throw new BusinessLogicError(ErrorCode.CONFIG_NOT_FOUND);
    }

    const results = [];
    for (const customerConfig of customers) {
      const item: CreateSurchargeFeeSettingInput = this.buildItemFromConfig(shared, customerConfig);
      const created = await this.create(item);
      if (Array.isArray(created)) {
        results.push(...created);
      } else {
        results.push(created);
      }
    }

    return results;
  }

  private buildItemFromConfig(
    shared: Omit<CreateManySurchargeFeeSettingsInput, 'customers'>,
    customerConfig: CreateSurchargeFeeSettingCustomerConfigInput,
  ): CreateSurchargeFeeSettingInput {
    return {
      ...shared,
      customerType: customerConfig.customerType,
      details: customerConfig.details,
      amount: customerConfig.amount,
    };
  }

  async insertMany(req: CreateSurchargeFeeSettingInput[], hotel?: Hotel) {
    const items = [];
    for (const input of req) {
      const item = new SurchargeFeeSetting();
      Object.assign(item, input);
      if (!item.customerType) item.customerType = CustomerType.ADULT;
      if (item.details) {
        item.details = this.normalizeDetails(item.details);
      }
      this.validateDetails(item.details);
      if (hotel) item.hotel = hotel;
      items.push(item);
    }

    return this.repo.insertMany(items);
  }
