    qb.andWhere(
      `ARRAY(
        SELECT sfsc."geoCountryId"
        FROM surcharge_fee_setting_countries sfsc
        WHERE sfsc."surchargeFeeSettingId" = sfs.id
        ORDER BY sfsc."geoCountryId"
      ) = :countryIds::int[]`,
      { countryIds: countryIds.sort((a, b) => a - b) },
    );

    // Check exact match cho rooms (M2M relation)
    qb.andWhere(
      `ARRAY(
        SELECT sfsr."roomId"
        FROM surcharge_fee_setting_rooms sfsr
        WHERE sfsr."surchargeFeeSettingId" = sfs.id
        ORDER BY sfsr."roomId"
      ) = :roomIds::int[]`,
      { roomIds: roomIds.sort((a, b) => a - b) },
    );

